3_real_world_example.code:
const parent = document.getElementById('parent');
const child = document.getElementById('child');

// This will run FIRST, because it listens during Capture phase
parent.addEventListener('click', () => {
  console.log('Parent Capture Phase!');
}, { capture: true });

// This runs SECOND, when it hits the target
child.addEventListener('click', () => {
  console.log('Child clicked!');
});

// This runs THIRD, during the Bubbling phase
parent.addEventListener('click', () => {
  console.log('Parent Bubbling Phase!');
});

